-- Enrichment marathon batch: Yoast SEO, You.com, YouCanBookMe, Youform, YouTrack, youtube-dl-nas, YugabyteDB, YunoHost

-- ── Yoast SEO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Yoast SEO is the most widely installed WordPress SEO plugin, giving writers real-time optimization guidance, readability analysis, automatic XML sitemaps, and built-in schema markup directly inside the WordPress editor.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plugin; Premium is EUR 118.80 (about $129) per year per site$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Wijchen, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Yoast SEO Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Yoast SEO offers WordPress users in 2026: free and Premium features, pricing, readability analysis, schema markup and how it compares to rivals.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yoast SEO is a WordPress plugin that helps writers and site owners optimize on-page content for search engines without needing deep SEO expertise. It was created by Dutch SEO consultant Joost de Valk in 2010 and is developed by Yoast, a company headquartered in Wijchen, Netherlands. The plugin is one of the most downloaded WordPress plugins of all time, with millions of active installations across blogs, publishers, e-commerce stores and agency-managed sites. Yoast SEO ships as a free plugin available through the WordPress.org repository, alongside a paid Premium upgrade priced at EUR 118.80 (roughly $129) per year per website. The free version covers core on-page SEO fundamentals: a traffic-light style content analysis that scores keyphrase usage in the title, meta description, headings and body copy; a readability analysis that flags long sentences, passive voice, missing transition words and dense paragraphs across more than twenty-five supported languages; automatically generated and self-updating XML sitemaps; and built-in structured data (schema.org) markup covering articles, organizations, breadcrumbs, FAQ blocks and how-to blocks so pages are eligible for rich results in Google Search. Yoast SEO Premium adds automation aimed at saving time on larger sites: a redirect manager that lets editors create 301 redirects when URLs change or content is deleted, avoiding broken links and lost rankings; internal linking suggestions that recommend relevant existing pages to link to while a new post or page is being written; AI-generated suggestions for SEO titles and meta descriptions; and the ability to optimize a single piece of content for up to five keyphrases and their synonyms instead of just one. Premium subscribers also get one bundled seat for the Google Docs integration, 24/7 access to Yoast's support team, and the companion Local SEO, News SEO and Video SEO add-on plugins at no extra cost. Yoast SEO works alongside the standard WordPress publishing workflow and major page builders and themes, and it is commonly paired with WooCommerce for product pages. Because pricing is per site, agencies and businesses running many WordPress properties need a Premium license for each domain, which is the most commonly cited downside. Overall, Yoast SEO is best understood as an in-editor SEO coach: it does not replace technical SEO auditing or link-building tools, but it standardizes on-page SEO hygiene (titles, metadata, readability, sitemaps and schema) for non-technical content teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2490007c-e3b7-41a2-a1fb-ad0b93df009d';

