-- ── You.com ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$You.com is an AI search and research platform, founded by former Salesforce AI leaders, that grounds chatbot answers in real-time web citations and offers ARI, a multi-source AI research agent for enterprise report generation.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Palo Alto, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$You.com Review 2026: AI Search, ARI Research Agent and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what You.com does in 2026: AI-powered search, model-agnostic chat, the ARI research agent, and how its pricing has shifted toward enterprise API access.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$You.com is an AI search and research company founded in 2020 by Richard Socher (former Chief Scientist at Salesforce) and Bryan McCann, and headquartered in Palo Alto, California. It opened to public beta in November 2021 as a privacy-oriented alternative to conventional search engines, combining a chat-style assistant with live web retrieval so that answers are grounded in citations rather than generated purely from a model's training data. A defining characteristic of You.com is that it is model agnostic: rather than committing to a single underlying large language model, the product lets users route queries to models from providers such as OpenAI, Anthropic and Google, alongside You.com's own proprietary research and retrieval agents. In February 2025, You.com launched ARI (Advanced Research and Insights), a deep-research AI agent aimed at regulated industries and enterprise research teams. ARI is designed to scan hundreds of public and private sources in a single research task, then synthesize a polished report complete with citations, charts and visualizations in a few minutes, a workflow the company positions as faster and broader in source coverage than comparable deep-research agents from other AI labs. This shift toward enterprise research and retrieval has coincided with You.com's business model moving away from a consumer subscription search product. Where the company previously offered a free consumer tier plus a Pro plan around $20 per month with access to multiple AI models and larger context windows, by mid-2026 the consumer-facing pricing page had been retired, reflecting a broader pivot toward usage-based API pricing for developers and enterprise customers building on top of You.com's retrieval and research infrastructure. The company has continued to raise capital to support this enterprise pivot: in September 2025 it closed a $100 million Series C round led by Cox Enterprises at a reported $1.5 billion valuation, giving it unicorn status. For SEO and content teams evaluating You.com as a competitor to Google, Perplexity or ChatGPT search features, the relevant distinctions are its citation-first answer format, its multi-model routing, and its increasing enterprise focus through ARI rather than a purely consumer search replacement.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ea1262a4-d760-4eec-88e1-896425d5ac44';

