-- ── YouCanBookMe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$YouCanBookMe is an online appointment scheduling tool that turns a calendar into a customizable booking page, handling availability, reminders, payments and team round-robin scheduling.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Individual plan from $9/month$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Bedford, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$YouCanBookMe Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore YouCanBookMe in 2026: booking page features, calendar integrations, team scheduling and pricing plans from Free through Team tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$YouCanBookMe is an online scheduling and appointment booking tool that connects to a user's calendar (Google Calendar, Outlook or others) and turns it into a public-facing booking page where clients or colleagues can find and reserve an available meeting time. The company was founded in 2011 and is headquartered in Bedford, in Bedfordshire, United Kingdom. YouCanBookMe was later acquired by Capacity, an AI-powered customer support automation platform, which expanded its own scheduling capabilities through the acquisition. The product's core workflow is to sync with a user's existing calendar so that only genuinely free time is exposed to bookers, automatically preventing double-booking. Beyond basic scheduling, YouCanBookMe supports customizable booking pages with branded colors, backgrounds and footers, automated confirmation and reminder emails and SMS messages, and native video conferencing integrations with Zoom, Microsoft Teams and Google Meet. It also supports Stripe payment collection at the time of booking, group and round-robin scheduling for teams, password-protected booking pages, and a Chrome browser extension. Pricing follows a freemium structure across four tiers. The Free plan includes one calendar connection and one booking page with core scheduling features. The Individual plan adds more calendar connections and booking pages plus custom branding and premium support. The Professional plan, aimed at growing businesses, adds automated workflows, unlimited custom form questions, promotional codes, a HubSpot integration, access to Zapier for connecting over a thousand other tools, and analytics. The Team plan, YouCanBookMe's most popular tier for organizations, adds team member management, role-based access control, round-robin scheduling that distributes bookings across a team, centralized billing, unlimited API access and personalized onboarding. Pricing is offered with monthly billing, a 10 percent discount for annual billing, and a 20 percent discount for two-year commitments, alongside a 14-day free trial that requires no credit card. Typical customers include consultants, coaches, recruiters, agencies and sales or customer success teams that need clients or prospects to self-schedule meetings without back-and-forth email threads.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '523ab821-6dbc-4f0a-ad9c-477f20ab7e52';

