-- ── Youform ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Youform is an affordable online form and survey builder positioned as a Typeform alternative, offering unlimited forms and responses on a free plan plus conditional logic, payments and team collaboration on paid tiers.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Pro from $20/month billed annually ($29/month billed monthly)$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Youform Review 2026: Features, Pricing and Typeform Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Youform offers in 2026: unlimited free forms, conditional logic, Stripe payments and pricing across Free, Pro and Business plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Youform is an online form and survey builder created in 2023 with the explicit goal of being a fairly priced Typeform alternative that still offers a polished interface and user experience. The company is led by co-founders based in the United States (Pennsylvania) and India (Bangalore), operating as a distributed team rather than from a single traditional headquarters. Youform's core differentiator is its free tier: unlike many competing form builders that cap free-tier response volume, Youform's Free plan offers unlimited forms and unlimited responses at no cost, requiring no credit card to start. The free plan also includes conditional logic and calculations, integrations with Google Sheets, Slack, Zapier and webhooks, file uploads up to 10MB, calendar-booking integrations with Calendly, Cal.com and SavvyCal, and a single user account. Paid tiers unlock features aimed at businesses and teams. The Pro plan, priced at $29 per month billed monthly or $20 per month billed annually ($240 per year), adds custom branding and logo removal, Stripe payment collection within forms, custom domains and fonts, partial submission tracking with refill links so respondents can resume an incomplete form, advanced analytics including drop-off rates, and support for up to three team members. The Business plan, priced at $89 per month billed monthly or $60 per month billed annually ($720 per year), adds identity verification features such as email one-time-password verification and phone verification via SMS (which requires a personal Twilio account), an activity log with CSV export for auditing changes, and five included team members, with additional seats available at $10 per month each. Youform is typically evaluated against Typeform, Google Forms, Tally and Jotform, and its main selling points relative to those competitors are the unlimited free response volume and a modern, minimal editing interface. It suits freelancers, small businesses, indie makers and teams that need survey, feedback, lead-generation or intake forms without paying premium form-builder pricing for basic usage.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'acb5fd7b-7099-4d41-a28a-be19f1114546';

