-- ── YouTrack ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$YouTrack is JetBrains' issue tracking and project management tool, supporting Agile boards, Gantt timelines, time tracking, a knowledge base and AI-assisted features for software and cross-functional teams.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 10 users; paid Cloud plans from about $3.67 per user per month billed annually$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$YouTrack Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what JetBrains YouTrack offers in 2026: Agile boards, Gantt timelines, time tracking, AI features, and pricing from a free 10-user plan to paid Cloud tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$YouTrack is an issue tracking and project management tool developed by JetBrains, the software company behind IntelliJ IDEA and other developer tools, founded in 2000 and headquartered in Prague, Czech Republic. YouTrack itself was first released on October 29, 2009, as a keyboard-centric bug and issue tracker, and has since expanded into a broader project management platform used by more than 100,000 companies, spanning software development, DevOps, HR, marketing and other cross-functional teams. YouTrack offers Scrum and Kanban board presets alongside fully customizable boards, an interactive Gantt timeline for scheduling tasks, setting estimates and tracking dependencies, built-in time tracking, and a knowledge base for documentation. It also includes a HelpDesk module and a set of AI-assisted features, including text-to-issue transformation that converts natural-language descriptions into structured issues, writing assistance that checks grammar and spelling, and an AI assistant that can summarize content within tasks, articles and support tickets. On pricing, YouTrack remains free for teams of up to 10 users, with the full feature set available regardless of deployment as either YouTrack Cloud or a self-hosted Server installation. This free tier includes Kanban and Scrum boards, time tracking, the knowledge base, custom fields and REST API access without restriction. For teams larger than 10 users, YouTrack Cloud pricing starts at approximately $3.67 per user per month when billed annually, or a slightly higher rate around $3.50 to $5.40 per user per month depending on billing terms, following a price adjustment that took effect October 1, 2025, marking the first pricing change since the plan's prior structure had been stable for roughly five years. Self-hosted Server licensing is also available for organizations that need to keep issue data on their own infrastructure. YouTrack is commonly compared to Jira, Linear and Asana, and its differentiators are its flexible, highly customizable workflow engine, its keyboard-driven interface inherited from its original design, and JetBrains' broader ecosystem integration with tools like TeamCity, Space and the JetBrains IDEs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2f12a930-1f2e-4928-8d88-770f30751680';

