-- ── youtube-dl-nas ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$youtube-dl-nas is a small open-source, self-hosted queue server that runs in Docker on a NAS or home server, letting authenticated users submit YouTube download jobs processed by yt-dlp via a web and WebSocket interface.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$youtube-dl-nas: Self-Hosted YouTube Download Queue for Your NAS$q$, seo_title),
  seo_meta_description = COALESCE($q$youtube-dl-nas is a free, open-source Docker tool for running a queued, authenticated YouTube download server on a home NAS, built on yt-dlp.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$youtube-dl-nas is a free, open-source, self-hosted project maintained by developer hyeonsangjeon on GitHub. It provides an asynchronous WebSocket-based queue server for downloading YouTube videos to a private network-attached storage (NAS) device or home server, packaged as a ready-to-run Docker container. It is a hobby and community-maintained tool rather than a commercial product; it has no known company, headquarters, funding or employee count behind it, and should not be characterized as a business. The project was created to solve a specific practical problem: running a download tool as an exposed web service on a home NAS without proper access control invites abuse, so youtube-dl-nas requires user authentication (accounts created at container setup time) before accepting download requests. Once authenticated, users submit YouTube URLs, and the server processes them through a queue to prevent overload, with real-time status updates delivered over a WebSocket connection so the requester can watch the download's progress rather than polling a page. The project is built on Python 3 and runs on Debian Linux inside its Docker image. It downloads video at resolutions up to 2160p (4K) or can extract audio only, and it supports batch submissions with resume capability if a download is interrupted. A notable technical detail is that the underlying extraction engine was migrated from the original, now largely unmaintained youtube-dl library to yt-dlp, a more actively maintained fork with better error handling and faster adaptation to changes on YouTube's side; the project also automates daily updates to yt-dlp to keep pace with YouTube's frequent site changes that can otherwise break downloaders. A REST API is also available for programmatic interaction with the queue server, in addition to its web UI. Because it is entirely open source and self-hosted, there is no subscription, license fee or vendor lock-in: users deploy their own Docker container on their own hardware, and the developer's role is limited to maintaining the codebase on GitHub rather than operating a hosted service. Given its scope, it is best suited to hobbyists and home-lab or NAS enthusiasts who already run Docker and want a simple, access-controlled way to queue YouTube downloads for personal archival use, rather than to businesses or teams looking for a commercially supported product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3ee38403-9c79-4f01-b843-b92c0873dc50';

