-- ── YunoHost ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$YunoHost is a free, volunteer-maintained self-hosted server operating system built on Debian GNU/Linux that simplifies installing and administering your own web apps, email, file sync and other services.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$YunoHost Review 2026: Self-Hosted Server OS Features and Setup$q$, seo_title),
  seo_meta_description = COALESCE($q$See what YunoHost offers in 2026: a free, Debian-based self-hosting operating system with a one-click app catalog, SSO/LDAP, and email and file-sync support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$YunoHost is a free, open-source operating system built on top of Debian GNU/Linux, designed to simplify the administration of a personal or small-organization server and make self-hosting accessible to people without deep system administration expertise. The project originated in February 2012, when a developer known as Kload began building an admin interface for a friend's server, and it grew from that practical starting point into a broader, community-driven distribution. YunoHost is copylefted libre software maintained entirely by volunteers; it is explicitly not a company or for-profit entity, so it has no headquarters, employee count or funding round to report. The name YunoHost is a play on the internet meme phrase 'Y U NO,' reflecting the project's origins as a community response to the difficulty of self-hosting. Technically, YunoHost provides a webadmin interface and a command-line tool (the yunohost command) for managing a server, alongside an application catalog of pre-packaged software that can be installed in a few clicks rather than manually configured. Example applications available through the catalog include blogging platforms, cloud file storage and sync tools such as Nextcloud, personal websites, RSS readers, email services, and collaborative office suites like OnlyOffice and Collabora that integrate with Nextcloud. A key feature is built-in single sign-on (SSO) and LDAP integration: applications packaged for YunoHost that support user registration can hook into YunoHost's central user directory, so a person who logs into the YunoHost user portal is automatically authenticated across all connected apps rather than needing separate credentials for each one. YunoHost also handles general domain, website and email management tasks, such as configuring DNS, TLS certificates and mail delivery, which are traditionally some of the most error-prone parts of running a personal server. Because it is entirely free and open source, there is no pricing tier or subscription; the only cost to a user is the hardware or hosting they choose to run YunoHost on, such as a Raspberry Pi, an old computer or a rented virtual private server. YunoHost is best suited to privacy-conscious individuals, digital rights advocates and small communities who want to run their own services (file sync, email, blogs, chat) instead of relying on third-party SaaS platforms, and who are comfortable with basic server administration even though YunoHost substantially lowers that bar compared to manual Linux server setup.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0aa25628-95fd-4484-a51f-ba231959a576';

