INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Real-time SEO analysis$q$, $q$Scores keyphrase usage in the title, meta description, headings and body text with a traffic-light system while content is being written.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Readability analysis$q$, $q$Flags long sentences, passive voice, missing transition words and dense paragraphs across more than twenty-five supported languages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Automatic XML sitemaps$q$, $q$Generates and keeps sitemaps up to date automatically whenever pages or posts are added, updated or removed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Built-in schema markup$q$, $q$Adds structured data for articles, organizations, breadcrumbs, FAQ blocks and how-to blocks to help pages earn rich results.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Redirect manager (Premium)$q$, $q$Lets editors create 301 redirects when URLs change or pages are deleted, without needing a developer or separate plugin.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Internal linking suggestions (Premium)$q$, $q$Recommends relevant existing pages to link to while a new post or page is being drafted.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$AI title and description suggestions (Premium)$q$, $q$Generates suggested SEO titles and meta descriptions using AI, which editors can accept or edit.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Multiple keyphrase optimization (Premium)$q$, $q$Allows a single page to be optimized for up to five keyphrases and their synonyms instead of just one.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Deep integration with the WordPress editor gives instant, actionable feedback while content is being written$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$The free version already covers core SEO fundamentals most small sites need: sitemaps, schema and content analysis$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Large support community, extensive documentation and frequent updates aligned with WordPress core changes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Premium automation, such as redirects, internal linking suggestions and AI snippets, addresses genuine time-saving needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Trusted at scale, with millions of active installs, so it is well tested against WordPress and search engine changes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Premium is licensed per site, so agencies managing many WordPress properties face a recurring cost per domain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Redirect management, internal linking suggestions and AI snippet generation are all locked behind the paid tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Advanced SEOs sometimes find the analysis rules too rigid for content that intentionally breaks conventional structure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Only works within WordPress, so it offers no value outside that specific CMS ecosystem$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Is Yoast SEO free to use?$q$, $q$Yes. The core Yoast SEO plugin is free and includes content analysis, readability analysis, XML sitemaps and basic schema markup. Premium is an optional paid upgrade.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$What does Yoast SEO Premium add over the free version?$q$, $q$Premium adds a redirect manager, internal linking suggestions, AI-generated titles and descriptions, optimization for up to five keyphrases per page, and 24/7 support, plus bundled Local SEO, News SEO and Video SEO add-ons.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$How much does Yoast SEO Premium cost?$q$, $q$Yoast SEO Premium is EUR 118.80 (about $129) per year, billed per website.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Does Yoast SEO generate XML sitemaps automatically?$q$, $q$Yes, both the free and Premium versions generate XML sitemaps automatically and keep them updated as content changes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Does Yoast SEO add schema markup to my pages?$q$, $q$Yes. It automatically adds structured data for articles, organizations, breadcrumbs, and FAQ and how-to blocks, which can help pages qualify for rich results.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Can Yoast SEO optimize a page for more than one keyword?$q$, $q$The free version optimizes for one keyphrase per page. Premium allows optimization for up to five keyphrases and their synonyms on a single page.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Does Yoast SEO work with any WordPress theme or page builder?$q$, $q$Yoast SEO is designed to work broadly across WordPress themes and popular page builders, since it hooks into the standard WordPress editor and content fields rather than a specific theme.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Who develops Yoast SEO?$q$, $q$Yoast SEO is developed by Yoast, a company founded by Joost de Valk in 2010 and headquartered in Wijchen, Netherlands.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Blog and content publishing$q$, $q$Content teams use Yoast SEO to check keyphrase usage and readability before hitting publish, standardizing on-page SEO across many contributors.$q$, $q$Bloggers and content marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$E-commerce product and category pages$q$, $q$Store owners use Yoast SEO alongside WooCommerce to optimize product titles, descriptions and schema so listings are more discoverable in search.$q$, $q$Online store owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Multi-site agency SEO management$q$, $q$Agencies install Yoast SEO across client WordPress sites to enforce consistent metadata, sitemaps and schema without training every client on SEO basics.$q$, $q$SEO and digital marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["SEO content analysis","Readability analysis","Automatic XML sitemaps","Core schema markup (articles, breadcrumbs, organization)","Single keyphrase optimization per page"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$Premium$q$, $q$EUR 118.80 (about $129) per site$q$, $q$annual$q$, NULL, $q$["Everything in Free","Redirect manager","Internal linking suggestions","AI-generated titles and meta descriptions","Optimization for up to 5 keyphrases per page","Local SEO, News SEO and Video SEO add-ons included","One Google Docs integration seat","24/7 support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$overview$q$, $q$What Is Yoast SEO$q$, 2, ARRAY[$q$Yoast SEO is a WordPress plugin that adds an on-page SEO and readability checker directly to the post and page editor. As a writer types, the plugin scores how well the content targets a chosen keyphrase and flags readability issues, giving green, orange or red indicators that make optimization approachable for non-specialists.$q$, $q$The plugin was launched in 2010 by Dutch SEO consultant Joost de Valk and has grown into one of the most installed plugins in the WordPress ecosystem, used by bloggers, publishers, e-commerce stores and agencies managing client sites. Yoast the company is based in Wijchen, Netherlands.$q$, $q$Yoast SEO is distributed as a free plugin through the official WordPress.org plugin repository, with an optional Premium upgrade that unlocks automation such as redirect management, internal linking suggestions, and AI-assisted title and description writing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free version covers the fundamentals of on-page SEO: keyphrase and readability analysis, automatically generated XML sitemaps that update whenever content is added or removed, and built-in schema.org structured data for articles, organizations, breadcrumbs, FAQ blocks and how-to blocks so pages can qualify for Google rich results.$q$, $q$Premium adds a redirect manager for handling changed or removed URLs, internal linking suggestions surfaced while writing, AI-generated title and meta description suggestions, and the ability to optimize one page for up to five keyphrases and their synonyms rather than a single target term.$q$, $q$Premium licenses also bundle the Local SEO, News SEO and Video SEO add-ons, one seat for the Google Docs integration, and access to 24/7 support from Yoast's team, which is useful for teams that rely on the plugin as their primary SEO workflow tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2490007c-e3b7-41a2-a1fb-ad0b93df009d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yoast SEO's free plugin has no cost and includes SEO analysis, readability analysis, XML sitemaps and core schema markup, making it usable indefinitely for small sites and hobby blogs.$q$, $q$Yoast SEO Premium costs EUR 118.80 (about $129) per year, billed annually per website. Agencies or businesses that run multiple WordPress sites need a separate Premium subscription for each domain.$q$, $q$There is no usage-based or team pricing tier; the plugin is licensed per site rather than per user, which keeps pricing simple but means the cost scales with the number of websites rather than the number of editors.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Citation-grounded chat answers$q$, $q$Responses are generated with live web retrieval and inline citations so users can verify sources rather than trusting an ungrounded answer.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Model-agnostic routing$q$, $q$Lets users and API customers choose or combine outputs from multiple large language model providers instead of one fixed model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$ARI deep research agent$q$, $q$Scans a large number of public and private sources for a single research task and produces a structured report with citations and visuals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Enterprise and private data grounding$q$, $q$Supports connecting private enterprise files and data sources so research and answers can incorporate internal documents alongside public web data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Interactive charts and visualizations$q$, $q$ARI-generated reports can include charts and graphics to summarize research findings rather than plain text alone.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$API access for developers$q$, $q$Exposes retrieval and research capabilities through an API so businesses can build search and research features into their own products.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Citation-first design makes it easier to verify AI-generated claims against original sources$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Model-agnostic approach avoids lock-in to a single AI provider's outputs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$ARI's multi-source research capability is positioned as faster and broader than some competing deep-research agents$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Backed by significant recent funding, suggesting continued investment in the research and retrieval product line$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Consumer pricing transparency has decreased, with no public pricing page for individual users by mid-2026$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$The pivot toward enterprise API and research use cases means casual consumer search users may find the product less clearly positioned$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$As with any AI search tool, answer quality still depends on the underlying models and the freshness of retrieved sources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Enterprise-focused features like ARI are aimed at business use cases, which may be less relevant for individual, everyday search needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$What is You.com?$q$, $q$You.com is an AI search and research platform that combines a chat assistant with live web retrieval and citations, plus an enterprise research agent called ARI.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Who founded You.com?$q$, $q$You.com was founded in 2020 by Richard Socher and Bryan McCann, both former Salesforce AI executives.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$What is ARI?$q$, $q$ARI (Advanced Research and Insights) is You.com's deep-research AI agent, launched in 2025, that scans large numbers of public and private sources to produce cited research reports with charts and visuals.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Is You.com free to use?$q$, $q$You.com previously offered a free consumer tier and a paid Pro plan, but by mid-2026 its consumer pricing page was no longer public as the company shifted toward enterprise and usage-based API pricing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Does You.com use its own AI model?$q$, $q$You.com is model agnostic, meaning it lets users and API customers route requests across multiple large language model providers rather than relying on a single proprietary model.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Where is You.com headquartered?$q$, $q$You.com is headquartered in Palo Alto, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$How is You.com funded?$q$, $q$You.com raised a $100 million Series C round led by Cox Enterprises in September 2025 at a reported $1.5 billion valuation.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Cited AI search and research$q$, $q$Users who want AI-generated answers backed by verifiable web citations rather than an ungrounded chatbot response.$q$, $q$Knowledge workers and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Enterprise deep research reports$q$, $q$Teams use ARI to produce multi-source research reports for market research, due diligence or regulated-industry analysis in minutes rather than hours.$q$, $q$Enterprise research and analyst teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Building search and research features via API$q$, $q$Developers integrate You.com's retrieval and research API into their own products to add grounded AI answers or research capabilities.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Free (legacy consumer tier)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Access to base AI chat and search","Limited model access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Pro (legacy consumer tier)$q$, $q$around $20/month (historical)$q$, $q$monthly$q$, NULL, $q$["Access to additional AI models","File uploads","Larger context windows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Enterprise / API$q$, $q$Custom, usage-based$q$, $q$custom$q$, NULL, $q$["ARI deep research agent access","Private data and enterprise file grounding","API access for retrieval and research","Custom contract terms"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$overview$q$, $q$What Is You.com$q$, 2, ARRAY[$q$You.com is an AI search and research platform that pairs a chat-style assistant with live web retrieval, so answers are grounded in cited sources rather than generated from a model's training data alone. It was founded in 2020 by Richard Socher and Bryan McCann, both formerly of Salesforce's AI research team, and is headquartered in Palo Alto, California.$q$, $q$The product opened to public beta in late 2021, positioning itself as a privacy-conscious alternative to mainstream search engines. Its defining technical choice is being model agnostic: users and API customers can route requests across different large language models from multiple providers rather than being locked into one.$q$, $q$In 2025, You.com introduced ARI, a deep-research AI agent aimed at professional and regulated-industry research work, marking a shift in the company's focus from consumer search toward enterprise research and retrieval infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$You.com's chat assistant grounds responses in real-time web citations, letting users verify claims against the original sources rather than trusting an ungrounded model output.$q$, $q$Because the platform is model agnostic, users and enterprise customers can select or blend outputs from multiple leading language models rather than being tied to a single vendor's model.$q$, $q$ARI, the company's research agent, can scan a large number of public and private sources for a single research task and assemble a structured report with citations, charts and visualizations, aimed at use cases like market research, due diligence and regulated-industry analysis.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$You.com's pricing has changed significantly over its history. It originally offered a free consumer tier alongside a Pro subscription priced around $20 per month, which unlocked access to additional AI models, file uploads and larger context windows.$q$, $q$By mid-2026 the consumer pricing page had been removed from public view, reflecting the company's pivot away from a seat-priced consumer search product.$q$, $q$Current commercial engagement is centered on usage-based API and enterprise licensing for the retrieval and ARI research capabilities, typically arranged directly with the company rather than through a self-serve public pricing page.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Calendar sync and conflict prevention$q$, $q$Connects to Google Calendar, Outlook and other calendars so only genuinely available times are shown to bookers, preventing double-booking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Customizable booking pages$q$, $q$Lets users brand their booking page with custom colors, backgrounds and footer content to match their business identity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Automated reminders and confirmations$q$, $q$Sends customizable email and SMS notifications automatically before and after a booking is made.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Video conferencing integrations$q$, $q$Automatically attaches Zoom, Microsoft Teams or Google Meet meeting links to bookings made through the page.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Stripe payment collection$q$, $q$Allows businesses to collect payment at the time of booking for paid consultations or appointments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Round-robin and group scheduling$q$, $q$Distributes incoming bookings evenly across a team or allows multiple people to book into a shared group session.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Automated workflows$q$, $q$On higher tiers, triggers follow-up actions and communications automatically based on booking events.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Zapier and HubSpot integrations$q$, $q$Connects bookings to over a thousand other tools via Zapier, or syncs directly with HubSpot on the Professional plan and above.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Free and Individual tiers make it accessible for solo consultants and freelancers before any real commitment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Strong calendar sync reliably prevents double-booking across multiple connected calendars$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Team plan's round-robin scheduling and centralized billing suit growing sales and customer success teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Native Stripe payment collection removes the need for a separate invoicing step for paid appointments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Zapier and HubSpot integrations extend the tool into existing sales and marketing workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Higher-value features like automated workflows, analytics and HubSpot integration require the Professional plan or above$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Per-user pricing on the Team plan can add up quickly for larger scheduling teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Some advanced customization options are only available on higher tiers, which may frustrate Free or Individual users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$As with most booking tools, non-technical users may need time to configure availability rules and buffer times correctly$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Is YouCanBookMe free?$q$, $q$Yes, YouCanBookMe offers a free plan with one calendar connection and one booking page. Paid plans start at $9/month for more connections and features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Does YouCanBookMe prevent double-booking?$q$, $q$Yes, it syncs with connected calendars in real time so only genuinely available times are shown on the booking page.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Can YouCanBookMe collect payments?$q$, $q$Yes, it integrates with Stripe so businesses can collect payment at the time of booking.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Does YouCanBookMe support teams?$q$, $q$Yes, the Team plan supports round-robin scheduling, role-based access, team member management and centralized billing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$What video conferencing tools does YouCanBookMe integrate with?$q$, $q$It natively integrates with Zoom, Microsoft Teams and Google Meet, automatically attaching meeting links to bookings.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Is there a free trial for paid plans?$q$, $q$Yes, YouCanBookMe offers a 14-day free trial on paid plans with no credit card required.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Who owns YouCanBookMe?$q$, $q$YouCanBookMe was acquired by Capacity, an AI-powered customer support automation platform, which expanded its scheduling capabilities through the acquisition.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Solo consultant and coach scheduling$q$, $q$Independent professionals share a single booking page so clients can self-schedule appointments during available times.$q$, $q$Consultants, coaches and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Sales and customer success team scheduling$q$, $q$Teams use round-robin scheduling to evenly distribute inbound meeting requests among available reps.$q$, $q$Sales and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Paid appointment booking$q$, $q$Service businesses collect payment through Stripe at the moment a client books a paid appointment or consultation.$q$, $q$Service-based businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["1 calendar connection","1 booking page","Zoom, Teams and Google Meet integration","Customizable emails and SMS","Stripe payments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Individual$q$, $q$From $9/month$q$, $q$monthly$q$, NULL, $q$["2 calendar connections","2 booking pages","Custom branding","Group sessions","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Professional$q$, $q$Contact for current pricing$q$, $q$monthly or annual$q$, NULL, $q$["6 calendar connections","10 booking pages","Automated workflows","HubSpot integration","Zapier access","Analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$Team$q$, $q$Per member, contact for current pricing$q$, $q$monthly or annual$q$, NULL, $q$["10 calendar connections per user","15+ booking pages per user","Round-robin scheduling","Role-based access","Centralized billing","Unlimited API access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$overview$q$, $q$What Is YouCanBookMe$q$, 2, ARRAY[$q$YouCanBookMe is an online scheduling tool that connects to a user's existing calendar and generates a shareable booking page, letting clients, prospects or colleagues pick an available meeting time without email back-and-forth.$q$, $q$The company was founded in 2011 and is headquartered in Bedford, United Kingdom. It was later acquired by Capacity, an AI-powered customer support automation platform, which expanded its own scheduling features through the acquisition.$q$, $q$YouCanBookMe is aimed at individuals, small teams and larger organizations alike, with plans that scale from a single free booking page up to team-wide round-robin scheduling and centralized billing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of the product is calendar syncing that prevents double-booking by only exposing genuinely free times, combined with a customizable booking page that can reflect a brand's colors, background and footer content.$q$, $q$Automated confirmation and reminder communications go out by email and SMS, and native integrations with Zoom, Microsoft Teams and Google Meet automatically attach video conferencing details to booked meetings.$q$, $q$Team-oriented features include group sessions, round-robin distribution of bookings across team members, role-based access control, and workflow automation for higher-tier plans, alongside Stripe payment collection for paid appointments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('523ab821-6dbc-4f0a-ad9c-477f20ab7e52', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$YouCanBookMe offers four tiers: Free (one calendar connection, one booking page), Individual (from $9/month, more connections and branding), Professional (adds automation, HubSpot and Zapier integrations, and analytics), and Team (adds team management, round-robin scheduling and unlimited API access).$q$, $q$All paid plans can be billed monthly, or discounted 10 percent for annual billing and 20 percent for two-year billing, and a 14-day free trial is available without requiring a credit card.$q$, $q$Because pricing rises with the number of calendar connections, booking pages and team members needed, small solo users can often stay on the Free or Individual tier, while agencies and sales teams typically need Professional or Team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Unlimited free forms and responses$q$, $q$The free plan does not cap the number of forms created or responses collected, unlike many competing form builders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Conditional logic and calculations$q$, $q$Lets form creators branch questions based on prior answers and perform calculations within the form, available even on the free plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Stripe payment collection$q$, $q$Pro and Business plans can collect payments directly within a form using Stripe.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Partial submission tracking and refill links$q$, $q$Pro plan and above can save incomplete responses and send respondents a link to resume where they left off.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Custom branding and domains$q$, $q$Removes Youform branding and supports custom domains and fonts so forms can match a business's identity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Identity verification$q$, $q$Business plan supports email one-time-password verification and SMS phone verification to confirm respondent identity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Advanced analytics$q$, $q$Pro plan and above include analytics with drop-off rate tracking to identify where respondents abandon a form.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Team collaboration$q$, $q$Paid plans support multiple team members working on the same forms, with an activity log available on the Business plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Free plan offers genuinely unlimited forms and responses, unlike most competitors that cap free-tier volume$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Modern, minimal interface comparable to Typeform at a lower price point$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Native Stripe payments and calendar-booking integrations reduce the need for separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Partial submission tracking with refill links helps recover otherwise-lost responses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Business plan's verification and audit-log features suit teams with compliance requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$As a newer company founded in 2023, it has a shorter track record than long-established form builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$SMS phone verification on the Business plan requires connecting a personal Twilio account, adding setup complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Advanced features like custom domains, payments and analytics are all locked behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$No single, traditional company headquarters may be a consideration for enterprise buyers requiring formal vendor documentation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Is Youform really free for unlimited responses?$q$, $q$Yes, the Free plan includes unlimited forms and unlimited responses with no credit card required to start.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$How much does Youform Pro cost?$q$, $q$Pro is $29/month billed monthly, or $20/month ($240/year) if billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Can Youform collect payments?$q$, $q$Yes, the Pro and Business plans support collecting payments directly within forms using Stripe.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Does Youform support conditional logic?$q$, $q$Yes, conditional logic and calculations are included even on the free plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$What does the Business plan add?$q$, $q$The Business plan adds email and SMS identity verification, an activity log with CSV export, and five team member seats, with additional seats available for $10/month each.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Is Youform a good Typeform alternative?$q$, $q$Youform positions itself specifically as a lower-cost Typeform alternative with a similar modern interface and an unlimited free response tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$When was Youform founded?$q$, $q$Youform was created in 2023.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Customer feedback and surveys$q$, $q$Businesses collect unlimited survey responses on the free plan without worrying about hitting a response cap.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Paid intake and application forms$q$, $q$Service businesses use Stripe-connected forms to collect payment alongside client intake information.$q$, $q$Freelancers and service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Lead generation forms$q$, $q$Marketing teams use conditional logic and custom branding to build on-brand lead capture forms embedded on their site.$q$, $q$Marketing teams and indie makers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Unlimited forms and responses","Conditional logic and calculations","Google Sheets, Slack, Zapier and webhook integrations","File uploads up to 10MB","Calendar integrations","1 user account"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Pro$q$, $q$$29/month ($20/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Free","Custom branding and logo","Stripe payment collection","Custom domains and fonts","Partial submissions and refill links","Advanced analytics with drop-off rates","Up to 3 team members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$Business$q$, $q$$89/month ($60/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Pro","Email OTP verification","SMS phone verification","Activity log with CSV export","5 team members included","Additional seats at $10/month each"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$overview$q$, $q$What Is Youform$q$, 2, ARRAY[$q$Youform is an online form and survey builder built as a more affordable alternative to Typeform, while aiming to keep a similarly clean and modern editing and response experience.$q$, $q$The product launched in 2023 and is run by a distributed team of co-founders based in the United States and India rather than from a single central headquarters.$q$, $q$Its standout feature is a genuinely unlimited free plan: forms and responses are not capped on the free tier, which differentiates it from many competing form builders that gate response volume behind a paywall.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Even on the free plan, Youform supports conditional logic, calculations, file uploads up to 10MB, and integrations with Google Sheets, Slack, Zapier, webhooks, and calendar-booking tools like Calendly, Cal.com and SavvyCal.$q$, $q$The Pro plan adds business-oriented features: custom branding and logo, Stripe payment collection inside forms, custom domains and fonts, partial submission tracking with refill links, and advanced analytics covering drop-off rates.$q$, $q$The Business plan layers on identity verification (email OTP and SMS phone verification), an activity log with CSV export for compliance and auditing, and support for larger teams with additional seats available.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb5fd7b-7099-4d41-a28a-be19f1114546', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Youform's Free plan costs nothing and includes unlimited forms and responses, making it usable indefinitely for individuals and small projects.$q$, $q$The Pro plan is $29/month billed monthly, or $20/month ($240/year) billed annually, and supports up to three team members plus payment collection and custom branding.$q$, $q$The Business plan is $89/month billed monthly, or $60/month ($720/year) billed annually, includes five team members with additional seats at $10/month each, and adds verification and audit-log capabilities aimed at larger or compliance-conscious teams.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Scrum and Kanban boards$q$, $q$Offers ready-made Agile board presets as well as fully customizable boards to match a team's existing process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Interactive Gantt timeline$q$, $q$Schedules and prioritizes tasks with estimates and dependencies, visualized on a timeline for precise progress tracking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Built-in time tracking$q$, $q$Captures effort logged against issues directly within the tracker without needing a separate time-tracking tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Knowledge base$q$, $q$Provides a built-in space for team documentation that lives alongside the issue tracker.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$HelpDesk module$q$, $q$Adds support-ticket handling capability so customer or internal support requests can be managed within YouTrack.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$AI text-to-issue transformation$q$, $q$Converts natural-language descriptions into structured, properly fielded issues automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$AI writing and summarization assistant$q$, $q$Checks grammar and spelling and generates summaries of content across tasks, articles and support tickets.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Custom fields and workflow automation$q$, $q$Supports custom fields and configurable workflows so YouTrack can adapt to processes beyond standard software development.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Free plan for up to 10 users includes the complete feature set, not a limited trial version$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Highly flexible workflow and custom field engine suits teams outside pure software development, including HR and marketing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Combines issue tracking, Gantt planning, knowledge base and HelpDesk in one tool, reducing the need for separate systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$AI-assisted features like text-to-issue and summarization can reduce manual ticket-writing overhead$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Backed by JetBrains, a long-established developer tools company with deep integration into its broader ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Recent price increase (effective October 2025) raises costs for teams above 10 users after years of stable pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Keyboard-centric, feature-dense interface can have a steeper learning curve than simpler task tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Less brand recognition among non-technical teams compared to Jira or Asana$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Self-hosted deployment requires more setup and maintenance effort than a pure SaaS competitor$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Is YouTrack free?$q$, $q$Yes, YouTrack is free for up to 10 users with the full feature set on both Cloud and self-hosted Server deployments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$How much does YouTrack cost for larger teams?$q$, $q$For teams larger than 10 users, YouTrack Cloud pricing starts at roughly $3.67 per user per month on annual billing, following a pricing update effective October 1, 2025.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Who makes YouTrack?$q$, $q$YouTrack is developed by JetBrains, a software company founded in 2000 and headquartered in Prague, Czech Republic.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Can YouTrack be self-hosted?$q$, $q$Yes, YouTrack is available both as a hosted Cloud product and as a self-hosted Server installation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Does YouTrack support Agile methodologies?$q$, $q$Yes, it includes Scrum and Kanban board presets as well as fully customizable boards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Does YouTrack include AI features?$q$, $q$Yes, it includes text-to-issue transformation, AI writing assistance, and an AI assistant that summarizes tasks, articles and tickets.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Is YouTrack only for software teams?$q$, $q$No, while it originated as a bug tracker, YouTrack is used across software development, DevOps, HR, marketing and other functions due to its customizable fields and workflows.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$When was YouTrack first released?$q$, $q$YouTrack was first released on October 29, 2009.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Software development issue tracking$q$, $q$Engineering teams track bugs, features and sprints using Scrum and Kanban boards integrated with time tracking.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Cross-functional project management$q$, $q$HR, marketing and operations teams use custom fields and workflows to manage non-engineering projects in the same tool.$q$, $q$Cross-functional business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Customer and internal support ticketing$q$, $q$Teams use the built-in HelpDesk module to manage support requests alongside engineering issues.$q$, $q$Support and IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Up to 10 users","Full feature set on Cloud or Server","Kanban and Scrum boards","Time tracking","Knowledge base","REST API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Cloud (11+ users)$q$, $q$From about $3.67/user/month$q$, $q$annual (monthly available at a higher rate)$q$, NULL, $q$["All Free plan features","Unlimited users","Gantt timeline","HelpDesk module","AI-assisted features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$Server (self-hosted)$q$, $q$Contact JetBrains for current pricing$q$, $q$annual license$q$, NULL, $q$["Self-hosted deployment","Full feature parity with Cloud","Data kept on customer infrastructure"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$overview$q$, $q$What Is YouTrack$q$, 2, ARRAY[$q$YouTrack is an issue tracking and project management tool built by JetBrains, first released in 2009 as a keyboard-centric bug tracker and since expanded into a general-purpose project management platform.$q$, $q$JetBrains, the company behind YouTrack, was founded in 2000 and is headquartered in Prague, Czech Republic. YouTrack itself is used by more than 100,000 companies across software development, DevOps, HR, marketing and other team functions.$q$, $q$The tool is available both as YouTrack Cloud, a hosted SaaS offering, and as a self-hosted Server installation for organizations that need to keep issue data on their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$YouTrack provides Scrum and Kanban board presets as well as fully custom boards, an interactive Gantt timeline for scheduling and dependency tracking, and built-in time tracking for capturing effort against tasks.$q$, $q$A built-in knowledge base and HelpDesk module let teams document processes and manage support requests alongside their issue tracker, rather than needing separate tools.$q$, $q$AI-assisted features include text-to-issue transformation that converts natural-language input into structured tickets, writing assistance for grammar and spelling, and an AI assistant that summarizes content across tasks, articles and tickets.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f12a930-1f2e-4928-8d88-770f30751680', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$YouTrack is free for up to 10 users with the full feature set, available on either Cloud or self-hosted Server deployments, including Kanban/Scrum boards, time tracking, the knowledge base and REST API access.$q$, $q$For teams larger than 10 users, YouTrack Cloud pricing starts at roughly $3.67 per user per month on annual billing, following a pricing update effective October 1, 2025, the first change after several years of stable pricing.$q$, $q$Self-hosted Server licenses are also available for organizations that need to run YouTrack on their own infrastructure rather than JetBrains' cloud.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Authenticated download queue$q$, $q$Requires user accounts created at container setup, preventing unauthorized use of the exposed download endpoint.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Asynchronous WebSocket queue server$q$, $q$Processes download jobs in a queue with real-time progress updates delivered over WebSocket rather than page polling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Docker-ready deployment$q$, $q$Ships as a ready-to-run Docker container designed specifically for NAS and home-server environments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$yt-dlp powered downloading$q$, $q$Uses yt-dlp, an actively maintained fork of youtube-dl, for more reliable extraction as YouTube changes its site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Automated daily yt-dlp updates$q$, $q$Automatically updates the underlying yt-dlp engine daily to reduce breakage from YouTube-side changes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Up to 4K and audio-only downloads$q$, $q$Supports downloading video at resolutions up to 2160p or extracting audio only.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Batch and resume support$q$, $q$Allows submitting multiple downloads at once and resuming interrupted downloads instead of restarting them.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$REST API access$q$, $q$Exposes a REST API for programmatic interaction with the download queue alongside the standard web interface.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Completely free and open source with no subscription or licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Authentication protects the download endpoint from abuse when self-hosted on a home network$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Actively kept compatible with YouTube changes via automated daily yt-dlp updates$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Docker packaging makes deployment on a NAS or home server straightforward for users already running Docker$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Maintained as a personal open-source project, so there is no commercial support or guaranteed uptime of maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Requires comfort with Docker and self-hosting; it is not a hosted, one-click consumer product$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Scope is narrow, limited to queued YouTube downloading rather than broader media management$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$As with any YouTube downloader, functionality can be disrupted by changes YouTube makes to its platform until the tool is updated$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Is youtube-dl-nas free?$q$, $q$Yes, it is a free, open-source project with no license fee or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Do I need Docker to run youtube-dl-nas?$q$, $q$Yes, it is distributed as a Docker container designed to be deployed on a NAS or home server running Docker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Does youtube-dl-nas require authentication?$q$, $q$Yes, user accounts are created at container setup time, and authentication is required before the server accepts download jobs, which prevents abuse of an exposed home-network endpoint.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$What download engine does youtube-dl-nas use?$q$, $q$It uses yt-dlp, an actively maintained fork of the original youtube-dl library, and automates daily updates to keep pace with YouTube changes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$What video quality can youtube-dl-nas download?$q$, $q$It supports resolutions up to 2160p (4K) as well as audio-only downloads.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Who maintains youtube-dl-nas?$q$, $q$It is maintained by an individual developer, hyeonsangjeon, as a community open-source project on GitHub, not by a company.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Does youtube-dl-nas have an API?$q$, $q$Yes, it provides a REST API for programmatic interaction with the download queue in addition to its web and WebSocket interface.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Personal media archiving on a NAS$q$, $q$Home-lab users queue YouTube downloads directly to their NAS storage for personal offline archives.$q$, $q$Home-lab and NAS hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Self-hosted download automation$q$, $q$Users who already self-host services on Docker add an authenticated download queue rather than running an insecure standalone script.$q$, $q$Self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Batch downloading for offline viewing$q$, $q$Users submit multiple video links at once to download in the background with resume support for interrupted jobs.$q$, $q$Individuals needing offline video access$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$Open Source$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Self-hosted Docker deployment","Authenticated download queue","WebSocket real-time status","Up to 4K and audio-only downloads","Batch and resume support","REST API access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$overview$q$, $q$What Is youtube-dl-nas$q$, 2, ARRAY[$q$youtube-dl-nas is a free, open-source Docker tool that runs a small, authenticated YouTube download queue server, designed specifically to be deployed on a home NAS or self-hosted server rather than a public cloud service.$q$, $q$It is maintained as a personal, community open-source project by developer hyeonsangjeon on GitHub, with no associated company, funding or employee headcount. It should be understood as a hobby and home-lab tool rather than a commercial SaaS product.$q$, $q$The tool addresses a specific risk of running a bare download script as an exposed web service: without authentication, a public download endpoint on a home network can be abused by anyone who finds it. youtube-dl-nas requires user accounts before accepting jobs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Downloads are processed through an asynchronous queue with real-time status updates delivered over a WebSocket connection, so users can watch progress rather than repeatedly refreshing a page.$q$, $q$The project runs on Python 3 and Debian Linux inside a Docker container, supports resolutions up to 2160p (4K) or audio-only extraction, and supports batch job submission with resume support if a download is interrupted partway through.$q$, $q$It was migrated from the original youtube-dl library to yt-dlp, a more actively maintained fork, and the container automates daily updates to yt-dlp so the tool keeps working as YouTube changes its site. A REST API is also available for programmatic use alongside the web interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$youtube-dl-nas is entirely free and open source, distributed via GitHub with no license fee, subscription or paid tier.$q$, $q$Because it is self-hosted, the only cost is whatever hardware and network resources the user's own NAS or server requires to run the Docker container.$q$, $q$There is no vendor to purchase support from; ongoing maintenance depends on the open-source project's community and its maintainer continuing to update the code.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ee38403-9c79-4f01-b843-b92c0873dc50', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$PostgreSQL compatibility$q$, $q$Supports PostgreSQL features including stored procedures, triggers and extensions, easing migration from existing PostgreSQL applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Automatic horizontal scaling$q$, $q$Distributes and shards data automatically across nodes without requiring manual sharding logic in the application.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Multi-region and multi-zone resilience$q$, $q$Can span availability zones or regions to withstand node, zone or region-level failures.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Dual query APIs (YSQL and YCQL)$q$, $q$Offers a PostgreSQL-compatible relational API (YSQL) alongside a Cassandra-inspired API (YCQL) for different workload types.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Open-source Community Edition$q$, $q$Provides a free, self-hostable version of the database under the Apache 2.0 license.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$YugabyteDB Aeon managed service$q$, $q$Fully managed database-as-a-service that can be deployed in Yugabyte's cloud or the customer's own cloud account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Consumption-based cloud pricing$q$, $q$Aeon pricing uses a unified credit-based consumption model applied consistently across deployment options.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Bring-your-own-cloud deployment$q$, $q$Aeon can be deployed into a customer's own cloud account rather than only Yugabyte-hosted infrastructure, supporting data residency needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Open-source core with a permissive Apache 2.0 license allows free, unrestricted self-hosted use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$PostgreSQL compatibility lowers the migration barrier for teams already using PostgreSQL$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Built-in horizontal scaling and multi-region resilience avoid the need for custom application-level sharding$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Aeon's bring-your-own-cloud option supports data residency and compliance requirements for global businesses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Founded by engineers with distributed systems experience from Facebook, lending credibility for mission-critical workloads$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Distributed SQL databases generally add operational complexity compared to a simple single-node PostgreSQL instance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Consumption-based Aeon pricing can be harder to predict upfront than flat per-seat or per-instance pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Full enterprise features and advanced multi-region capabilities are gated behind paid Professional-tier pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Teams need to evaluate YCQL versus YSQL carefully, since API choice affects tooling and ecosystem compatibility$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Is YugabyteDB open source?$q$, $q$Yes, the core YugabyteDB database is open source under the Apache 2.0 license and free to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Is YugabyteDB compatible with PostgreSQL?$q$, $q$Yes, YugabyteDB is runtime-compatible with PostgreSQL, supporting stored procedures, triggers and extensions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$What is YugabyteDB Aeon?$q$, $q$YugabyteDB Aeon is Yugabyte's fully managed cloud database service, offered with a free trial and consumption-based pricing thereafter.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$How is YugabyteDB Aeon priced?$q$, $q$Aeon uses a credit-based consumption model where 100 Consumption Units equal 1 YugabyteDB Credit worth $1 USD, applied across Standard and Professional tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Who founded Yugabyte?$q$, $q$Yugabyte was founded in February 2016 by former Facebook engineers Kannan Muthukkaruppan, Karthik Ranganathan and Mikhail Bautin.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Can YugabyteDB run across multiple regions?$q$, $q$Yes, it can distribute data across availability zones or regions to provide resilience to zone or region-level failures.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$What query languages does YugabyteDB support?$q$, $q$It supports YSQL, a PostgreSQL-compatible relational API, and YCQL, a Cassandra-inspired API.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Where is Yugabyte headquartered?$q$, $q$Yugabyte is headquartered in Sunnyvale, California.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Scaling beyond single-node PostgreSQL$q$, $q$Engineering teams whose application has outgrown a single-node PostgreSQL database migrate to YugabyteDB for built-in horizontal scaling.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Multi-region, mission-critical applications$q$, $q$Businesses running applications that must survive a full region outage deploy YugabyteDB across multiple regions for resilience.$q$, $q$Enterprises with high-availability requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Data residency and compliance-driven deployments$q$, $q$Organizations subject to data residency regulations use YugabyteDB Aeon's bring-your-own-cloud option to keep data in specific jurisdictions.$q$, $q$Regulated industries and global enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Community Edition$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Open-source, self-hosted deployment","Apache 2.0 license","YSQL and YCQL APIs","Horizontal scaling and multi-node distribution"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$YugabyteDB Aeon Standard$q$, $q$Usage-based (credit consumption); free trial available$q$, $q$consumption-based$q$, NULL, $q$["Fully managed cloud database","Seamless scalability","Availability-zone level resilience"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$YugabyteDB Aeon Professional$q$, $q$Usage-based (credit consumption); contact for details$q$, $q$consumption-based$q$, NULL, $q$["Advanced multi-region capabilities","Region-level failure resilience","Data residency and compliance support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$overview$q$, $q$What Is YugabyteDB$q$, 2, ARRAY[$q$YugabyteDB is an open-source, distributed SQL database designed for cloud-native applications that need to scale horizontally across nodes, availability zones or regions while retaining relational database guarantees.$q$, $q$It was created by Yugabyte, a company founded in February 2016 by former Facebook engineers Kannan Muthukkaruppan, Karthik Ranganathan and Mikhail Bautin, headquartered in Sunnyvale, California.$q$, $q$A defining feature is PostgreSQL runtime compatibility: YugabyteDB supports stored procedures, triggers and extensions in the same way PostgreSQL does, so many PostgreSQL-based applications can migrate with limited code changes while gaining distributed scalability.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$YugabyteDB automatically distributes and replicates data across nodes, and can span multiple availability zones or regions, providing resilience to node, zone or region-level failures without manual sharding in the application layer.$q$, $q$It exposes two query APIs: YSQL, which is PostgreSQL-compatible for relational workloads, and YCQL, a Cassandra-inspired API for teams with different query pattern needs.$q$, $q$The database is available as an open-source Community Edition for self-managed deployment, as well as through YugabyteDB Aeon, a fully managed cloud database service that can run in Yugabyte's public cloud or a customer's own cloud account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core YugabyteDB database is free and open source under the Apache 2.0 license, allowing unrestricted self-hosted use.$q$, $q$YugabyteDB Aeon, the managed cloud service, offers a free trial to explore a full dedicated cluster before committing to a paid plan.$q$, $q$Aeon's production pricing uses a consumption-based credit model, where 100 Consumption Units equal 1 YugabyteDB Credit worth $1 USD, applied consistently across a Standard tier for startups and scale-ups and a Professional tier for larger businesses needing multi-region and data residency capabilities.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$One-click application catalog$q$, $q$Installs pre-packaged applications like Nextcloud, blogs, RSS readers and websites through the webadmin without manual configuration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Built-in single sign-on and LDAP$q$, $q$Lets supported apps authenticate automatically against YunoHost's central user directory once a user logs into the user portal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Webadmin and command-line management$q$, $q$Provides both a graphical web interface and a yunohost command-line tool for server administration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Automated domain and TLS management$q$, $q$Handles DNS, TLS certificate issuance and website configuration to reduce common self-hosting setup errors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Email server management$q$, $q$Provides tools to configure and run a personal or small-organization email service on the same server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Backup and restore support$q$, $q$Applications integrated with YunoHost support standardized backup and restore operations through the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Collaborative office suite integration$q$, $q$Supports OnlyOffice and Collabora integration with Nextcloud for in-browser document editing on a self-hosted stack.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Debian-based, community-maintained core$q$, $q$Built on Debian GNU/Linux and maintained entirely by volunteer contributors as copylefted libre software.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Completely free and open source with no subscription cost beyond the hardware or hosting a user provides$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$One-click app catalog substantially lowers the barrier to self-hosting common services compared to manual Linux setup$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Built-in SSO and LDAP integration means users do not need separate logins for every self-hosted app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Automated domain, TLS and email configuration removes some of the most error-prone parts of running a server$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Community-driven and ethically focused, appealing to privacy-conscious users who want to avoid third-party SaaS platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$As a volunteer-maintained project, there is no paid support option or guaranteed response time for issues$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Still requires basic comfort with server administration concepts even though YunoHost simplifies the process$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Application quality and maintenance depend on individual community packagers, so not every app in the catalog is equally polished$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Running your own server means taking on responsibility for uptime, security patching and backups yourself$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Is YunoHost free?$q$, $q$Yes, YunoHost is completely free and open source with no license fee or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$What operating system is YunoHost based on?$q$, $q$YunoHost is based on Debian GNU/Linux.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Who maintains YunoHost?$q$, $q$YunoHost is maintained entirely by volunteers as a copylefted libre software project; it is not a company or for-profit entity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Can YunoHost run Nextcloud?$q$, $q$Yes, Nextcloud is one of the applications available in YunoHost's application catalog and can be installed in a few clicks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Does YunoHost support single sign-on across apps?$q$, $q$Yes, applications that support user registration can integrate with YunoHost's built-in LDAP and single sign-on, so one login works across connected apps.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Can YunoHost handle email hosting?$q$, $q$Yes, YunoHost includes tools to configure and manage a personal or small-organization email service on the same server.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$When was YunoHost created?$q$, $q$The project originated in February 2012.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$What hardware can I run YunoHost on?$q$, $q$YunoHost can run on a range of hardware, from a Raspberry Pi or repurposed old computer to a rented virtual private server.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Personal cloud and file sync$q$, $q$Individuals self-host Nextcloud through YunoHost to sync and store files privately instead of using third-party cloud storage.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Small community or organization services$q$, $q$Small groups run shared blogs, wikis and email on a single YunoHost server with unified login for members.$q$, $q$Small communities and nonprofits$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Home-lab and self-hosting learning$q$, $q$Hobbyists use YunoHost on a Raspberry Pi or old computer to learn self-hosting without manually configuring every service.$q$, $q$Home-lab hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$Open Source$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Free Debian-based server operating system","One-click application catalog","Built-in SSO and LDAP","Automated domain and TLS management","Email server management","Backup and restore support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$overview$q$, $q$What Is YunoHost$q$, 2, ARRAY[$q$YunoHost is a free, open-source operating system built on Debian GNU/Linux that simplifies the administration of a personal or small-organization server, aiming to bring self-hosting to people without deep system administration experience.$q$, $q$The project began in February 2012 when a developer known as Kload started building an admin interface for a friend's server, and it has since grown into a community-maintained distribution used by self-hosters worldwide.$q$, $q$YunoHost is copylefted libre software maintained entirely by volunteers rather than a company, so it has no headquarters, employee count or commercial funding to report.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A webadmin interface and command-line tool let users manage the server, and an application catalog offers pre-packaged software, including blogging platforms, cloud file sync tools like Nextcloud, personal websites, RSS readers and collaborative office suites such as OnlyOffice and Collabora, all installable in a few clicks.$q$, $q$Applications that support user registration can integrate with YunoHost's built-in single sign-on and LDAP user directory, so logging into the YunoHost user portal automatically authenticates a user across every connected app.$q$, $q$YunoHost also manages domain, website and email configuration, handling tasks like DNS, TLS certificates and mail delivery that are typically among the most error-prone parts of running a self-hosted server manually.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$YunoHost itself is completely free and open source, with no license fee, subscription or paid tier of any kind.$q$, $q$The only expense involved is whatever hardware or hosting a user chooses to run it on, ranging from a Raspberry Pi or repurposed old computer to a rented virtual private server.$q$, $q$Because there is no commercial entity behind YunoHost, there is also no paid support plan; help comes from community documentation and the volunteer-run project forum.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0aa25628-95fd-4484-a51f-ba231959a576', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
